from collections import defaultdict

class SLRParser:
 def __init__(self, productions):
 """Initialize SLR parser with grammar productions."""
 self.productions = productions # List of (lhs, rhs) tuples
 self.terminals = set()
 self.non_terminals = set()
 self.start_symbol = productions[0][0]
 self._analyze_grammar()

 def _analyze_grammar(self):
 """Extract terminals and non-terminals from grammar."""
 for lhs, rhs in self.productions:
 self.non_terminals.add(lhs)
 for symbol in rhs:
 if symbol.islower() or symbol in {'+', '*', '(', ')', 'id'}:
 self.terminals.add(symbol)
 else:
 self.non_terminals.add(symbol)
 self.terminals.add('$') # End marker

 def closure(self, items):
 """Compute closure of a set of LR(0) items."""
 closure_set = set(items)
 changed = True

 while changed:
 changed = False
 new_items = set()

 for (lhs, rhs, dot) in closure_set:
 if dot < len(rhs):
 next_symbol = rhs[dot]
 # If next symbol is non-terminal, add its productions
 if next_symbol in self.non_terminals:
 for prod_lhs, prod_rhs in self.productions:
 if prod_lhs == next_symbol:
 new_item = (prod_lhs, prod_rhs, 0)
 if new_item not in closure_set:
 new_items.add(new_item)
 changed = True

 closure_set.update(new_items)

 return closure_set

 def goto(self, items, symbol):
 """Compute goto(I, X) - move dot past symbol."""
 new_items = set()

 for (lhs, rhs, dot) in items:
 if dot < len(rhs) and rhs[dot] == symbol:
 new_items.add((lhs, rhs, dot + 1))

 return self.closure(new_items) if new_items else set()

 def compute_follow(self):
 """Compute FOLLOW sets for all non-terminals."""
 follow = {nt: set() for nt in self.non_terminals}
 follow[self.start_symbol].add('$')

 changed = True
 while changed:
 changed = False

 for lhs, rhs in self.productions:
 # For each production A -> αBβ
 for i, symbol in enumerate(rhs):
 if symbol in self.non_terminals:
 # Add First(β) - {ε} to Follow(B)
 if i + 1 < len(rhs):
 beta = rhs[i + 1:]
 first_beta = self._first(beta)
 before = len(follow[symbol])
 follow[symbol].update(first_beta - {'ε'})
 if len(follow[symbol]) > before:
 changed = True
 # If β can derive ε or β is empty, add Follow(A) to Follow(B)
 else:
 before = len(follow[symbol])
 follow[symbol].update(follow[lhs])
 if len(follow[symbol]) > before:
 changed = True

 return follow

 def _first(self, symbols):
 """Compute First set for a sequence of symbols."""
 first_set = set()

 for symbol in symbols:
 if symbol not in self.non_terminals:
 first_set.add(symbol)
 break
 else:
 # Add First of non-terminal (excluding ε initially)
 for lhs, rhs in self.productions:
 if lhs == symbol:
 if rhs == ('ε',) or rhs == ():
 if 'ε' not in first_set:
 first_set.add('ε')
 else:
 first_rhs = self._first(rhs)
 first_set.update(first_rhs - {'ε'})
 if 'ε' not in first_rhs:
 break
 else:
 continue
 break

 return first_set

 def build_parsing_table(self):
 """Build SLR parsing tables (ACTION and GOTO)."""
 # Augment grammar with new start production
 augmented_start = self.start_symbol + "'"
 aug_productions = [(augmented_start, (self.start_symbol,))] + self.productions

 # Build canonical collection of LR(0) items
 initial_item = (augmented_start, (self.start_symbol,), 0)
 C = [self.closure({initial_item})]

 # Compute goto for each state
 states = []
 for I in C:
 state_transitions = {}
 symbols = self.terminals | self.non_terminals
 for symbol in symbols:
 goto_I = self.goto(I, symbol)
 if goto_I and goto_I not in C:
 C.append(goto_I)
 if goto_I:
 state_transitions[symbol] = C.index(goto_I)
 states.append(state_transitions)

 # Compute FOLLOW sets
 follow = self.compute_follow()

 # Build ACTION and GOTO tables
 self.action = defaultdict(dict)
 self.goto = defaultdict(dict)

 for i, I in enumerate(C):
 for (lhs, rhs, dot) in I:
 # Shift actions
 if dot < len(rhs):
 symbol = rhs[dot]
 if symbol in self.terminals:
 j = states[i].get(symbol)
 if j is not None:
 self.action[i][symbol] = ('shift', j)
 # Reduce/Accept actions
 else:
 if lhs == augmented_start:
 self.action[i]['$'] = ('accept',)
 else:
 for terminal in follow[lhs]:
 self.action[i][terminal] = ('reduce', lhs, rhs)

 # GOTO transitions
 for nt in self.non_terminals:
 j = states[i].get(nt)
 if j is not None:
 self.goto[i][nt] = j

 return self.action, self.goto

 def parse(self, input_tokens):
 """Parse input tokens using SLR tables."""
 input_tokens = list(input_tokens) + ['$']
 stack = [0]
 output = []

 print(f"{'Stack':<25} {'Input':<20} {'Action'}")
 print("-" * 65)

 while True:
 s = stack[-1]
 a = input_tokens[0]

 action = self.action[s].get(a)

 if action is None:
 print(f"{' '.join(map(str, stack)):<25} {' '.join(input_tokens):<20} Error!")
 return False, output

 action_type = action[0]

 if action_type == 'shift':
 print(f"{' '.join(map(str, stack)):<25} {' '.join(input_tokens):<20} Shift {action[1]}")
 stack.append(a)
 stack.append(action[1])
 input_tokens.pop(0)

 elif action_type == 'reduce':
 lhs, rhs = action[1], action[2]
 print(f"{' '.join(map(str, stack)):<25} {' '.join(input_tokens):<20} Reduce {lhs} -> {' '.join(rhs)}")
 pop_count = len(rhs) * 2
 for _ in range(pop_count):
 stack.pop()
 s = stack[-1]
 stack.append(lhs)
 stack.append(self.goto[s].get(lhs, 0))
 output.append((lhs, rhs))

 elif action_type == 'accept':
 print(f"{' '.join(map(str, stack)):<25} {' '.join(input_tokens):<20} Accept")
 return True, output


# Example grammar: S -> CC, C -> cC | d
def main():
 # Define grammar productions (lhs, rhs tuple)
 productions = [
 ('S', ('C', 'C')),
 ('C', ('c', 'C')),
 ('C', ('d',)),
 ]

 parser = SLRParser(productions)

 print("=" * 50)
 print("SLR Parser - Building Tables")
 print("=" * 50)

 action, goto = parser.build_parsing_table()

 print("\nACTION Table:")
 for state, actions in sorted(action.items()):
 for terminal, act in actions.items():
 print(f" State {state}, Terminal '{terminal}': {act}")

 print("\nGOTO Table:")
 for state, gotos in sorted(goto.items()):
 for nt, next_state in gotos.items():
 print(f" State {state}, Non-terminal '{nt}': {next_state}")

 # Parse input: "ccd$"
 print("\n" + "=" * 50)
 print("Parsing Input: c c d $")
 print("=" * 50)

 success, output = parser.parse(['c', 'c', 'd'])

 print("\nParsing Result:", "Success" if success else "Failure")
 print("Reduction sequence:", output)


if __name__ == "__main__":
 main()

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

#define MAX_STATES 20
#define MAX_ITEMS 50
#define MAX_PROD 10
#define MAX_SYMBOLS 10

// Structure to represent an LR(0) item: A -> α•β
typedef struct {
 char lhs;
 char rhs[5];
 int dot_pos; // Position of dot (0 to strlen(rhs))
} LR0Item;

// Grammar production structure
typedef struct {
 char lhs;
 char rhs[5];
} Production;

// Parser state containing set of items
typedef struct {
 LR0Item items[MAX_ITEMS];
 int item_count;
} ParserState;

// ACTION types
typedef enum { SHIFT, REDUCE, ACCEPT, ERROR } ActionType;

// ACTION table entry
typedef struct {
 ActionType type;
 int value; // state for shift, production index for reduce
} ActionEntry;

// Global variables
Production grammar[MAX_PROD];
int num_productions = 0;

ParserState states[MAX_STATES];
int num_states = 0;

ActionEntry action_table[MAX_STATES][MAX_SYMBOLS];
int goto_table[MAX_STATES][MAX_SYMBOLS];

char terminals[] = {'c', 'd', '$', '\0'};
char non_terminals[] = {'S', 'C', '\0'};

// Initialize grammar
void init_grammar() {
 // S -> CC
 grammar[0].lhs = 'S';
 strcpy(grammar[0].rhs, "CC");

 // C -> cC
 grammar[1].lhs = 'C';
 strcpy(grammar[1].rhs, "cC");

 // C -> d
 grammar[2].lhs = 'C';
 strcpy(grammar[2].rhs, "d");

 num_productions = 3;
}

// Check if character is terminal
bool is_terminal(char c) {
 for (int i = 0; terminals[i] != '\0'; i++) {
 if (terminals[i] == c) return true;
 }
 return false;
}

// Check if character is non-terminal
bool is_non_terminal(char c) {
 for (int i = 0; non_terminals[i] != '\0'; i++) {
 if (non_terminals[i] == c) return true;
 }
 return false;
}

// Create a new LR(0) item
LR0Item make_item(char lhs, char *rhs, int dot) {
 LR0Item item;
 item.lhs = lhs;
 strcpy(item.rhs, rhs);
 item.dot_pos = dot;
 return item;
}

// Check if two items are equal
bool items_equal(LR0Item a, LR0Item b) {
 return (a.lhs == b.lhs && 
 strcmp(a.rhs, b.rhs) == 0 && 
 a.dot_pos == b.dot_pos);
}

// Add item to state if not already present
void add_item_to_state(ParserState *state, LR0Item item) {
 for (int i = 0; i < state->item_count; i++) {
 if (items_equal(state->items[i], item)) return;
 }
 state->items[state->item_count++] = item;
}

// Compute closure of a set of items
void compute_closure(ParserState *state) {
 bool changed = true;

 while (changed) {
 changed = false;

 for (int i = 0; i < state->item_count; i++) {
 LR0Item item = state->items[i];

 // If dot is before a non-terminal, add its productions
 if (item.dot_pos < strlen(item.rhs)) {
 char next_sym = item.rhs[item.dot_pos];

 if (is_non_terminal(next_sym)) {
 // Add all productions of this non-terminal
 for (int j = 0; j < num_productions; j++) {
 if (grammar[j].lhs == next_sym) {
 LR0Item new_item = make_item(grammar[j].lhs, grammar[j].rhs, 0);
 int old_count = state->item_count;
 add_item_to_state(state, new_item);
 if (state->item_count > old_count) {
 changed = true;
 }
 }
 }
 }
 }
 }
 }
}

// Compute goto(I, X)
ParserState compute_goto(ParserState *state, char symbol) {
 ParserState new_state = {0};

 // Find items where dot is before 'symbol'
 for (int i = 0; i < state->item_count; i++) {
 LR0Item item = state->items[i];

 if (item.dot_pos < strlen(item.rhs) && 
 item.rhs[item.dot_pos] == symbol) {
 // Move dot past symbol
 LR0Item moved = make_item(item.lhs, item.rhs, item.dot_pos + 1);
 add_item_state(&new_state, moved);
 }
 }

 compute_closure(&new_state);
 return new_state;
}

void add_item_state(ParserState *state, LR0Item item) {
 for (int i = 0; i < state->item_count; i++) {
 if (items_equal(state->items[i], item)) return;
 }
 state->items[state->item_count++] = item;
}

// Check if state already exists
int find_state(ParserState *target) {
 for (int i = 0; i < num_states; i++) {
 if (states[i].item_count != target->item_count) continue;

 bool match = true;
 for (int j = 0; j < target->item_count; j++) {
 if (!items_equal(states[i].items[j], target->items[j])) {
 match = false;
 break;
 }
 }
 if (match) return i;
 }
 return -1;
}

// Build canonical collection
void build_canonical_collection() {
 // Initial state: S' -> •S
 ParserState initial = {0};
 LR0Item start_item = make_item('S', "S", 0);
 add_item_to_state(&initial, start_item);
 compute_closure(&initial);

 states[num_states++] = initial;

 bool new_states_added = true;

 while (new_states_added) {
 new_states_added = false;

 for (int i = 0; i < num_states; i++) {
 // Try all grammar symbols
 char symbols[] = {'c', 'd', 'S', 'C', '\0'};

 for (int s = 0; symbols[s] != '\0'; s++) {
 char sym = symbols[s];

 ParserState goto_state = compute_goto(&states[i], sym);

 if (goto_state.item_count > 0) {
 int existing = find_state(&goto_state);

 if (existing == -1) {
 states[num_states++] = goto_state;
 new_states_added = true;
 }
 }
 }
 }
 }
}

// FOLLOW set computation (simplified)
void get_follow(char non_term, char *follow_set) {
 follow_set[0] = '\0';
 int count = 0;

 if (non_term == 'S') {
 follow_set[count++] = '$';
 }

 // For C: check productions where C appears on RHS
 for (int i = 0; i < num_productions; i++) {
 char *rhs = grammar[i].rhs;
 for (int j = 0; j < strlen(rhs); j++) {
 if (rhs[j] == non_term && j == strlen(rhs) - 1) {
 // C at end, add Follow of LHS
 char temp[10];
 get_follow(grammar[i].lhs, temp);
 for (int k = 0; temp[k] != '\0'; k++) {
 int found = 0;
 for (int l = 0; l < count; l++) {
 if (follow_set[l] == temp[k]) found = 1;
 }
 if (!found) follow_set[count++] = temp[k];
 }
 }
 }
 }
 follow_set[count] = '\0';
}

// Build SLR parsing tables
void build_parsing_tables() {
 // Initialize tables
 for (int i = 0; i < MAX_STATES; i++) {
 for (int j = 0; j < MAX_SYMBOLS; j++) {
 action_table[i][j].type = ERROR;
 goto_table[i][j] = -1;
 }
 }

 // Process each state
 for (int i = 0; i < num_states; i++) {
 ParserState *state = &states[i];

 for (int j = 0; j < state->item_count; j++) {
 LR0Item item = state->items[j];
 int dot = item.dot_pos;

 if (dot < strlen(item.rhs)) {
 // Shift action
 char next = item.rhs[dot];
 if (is_terminal(next)) {
 ParserState goto_st = compute_goto(state, next);
 int target = find_state(&goto_st);
 if (target >= 0) {
 // Find terminal index
 int tidx = 0;
 for (int t = 0; terminals[t] != '\0'; t++) {
 if (terminals[t] == next) { tidx = t; break; }
 }
 action_table[i][tidx].type = SHIFT;
 action_table[i][tidx].value = target;
 }
 }
 } else {
 // Reduce action
 if (item.lhs == 'S' && strcmp(item.rhs, "S") == 0) {
 // Accept
 int tidx = 2; // $
 action_table[i][tidx].type = ACCEPT;
 } else {
 // Find which production
 int prod_idx = -1;
 for (int p = 0; p < num_productions; p++) {
 if (grammar[p].lhs == item.lhs && 
 strcmp(grammar[p].rhs, item.rhs) == 0) {
 prod_idx = p;
 break;
 }
 }

 // Get FOLLOW set and add reduce actions
 char follow[10];
 get_follow(item.lhs, follow);

 for (int f = 0; f < strlen(follow); f++) {
 char term = follow[f];
 int tidx = 0;
 for (int t = 0; terminals[t] != '\0'; t++) {
 if (terminals[t] == term) { tidx = t; break; }
 }
 action_table[i][tidx].type = REDUCE;
 action_table[i][tidx].value = prod_idx;
 }
 }
 }
 }

 // GOTO transitions
 ParserState goto_s = compute_goto(state, 'S');
 ParserState goto_c = compute_goto(state, 'C');

 int s_target = find_state(&goto_s);
 int c_target = find_state(&goto_c);

 // Non-terminal indices: S=0, C=1
 if (s_target >= 0) goto_table[i][0] = s_target;
 if (c_target >= 0) goto_table[i][1] = c_target;
 }
}

// Parse input using SLR tables
bool parse_input(char *input) {
 int stack[50];
 int top = 0;
 stack[top] = 0; // Initial state

 char symbols[50];
 int sym_top = 0;

 int pos = 0;
 char current = input[pos];

 printf("\nParsing: %s\n", input);
 printf("%-20s %-15s %s\n", "Stack", "Input", "Action");
 printf("--------------------------------------------\n");

 while (1) {
 int state = stack[top];

 // Find terminal index
 int tidx = -1;
 for (int i = 0; terminals[i] != '\0'; i++) {
 if (terminals[i] == current) { tidx = i; break; }
 }

 if (tidx == -1) {
 printf("Error: Unknown terminal\n");
 return false;
 }

 ActionType act = action_table[state][tidx].type;

 // Print current state
 printf("[");
 for (int i = 0; i <= top; i++) printf("%d ", stack[i]);
 printf("] ");
 printf("%-15s ", input + pos);

 if (act == SHIFT) {
 int next_state = action_table[state][tidx].value;
 printf("Shift %d\n", next_state);

 symbols[sym_top++] = current;
 stack[++top] = next_state;
 current = input[++pos];

 } else if (act == REDUCE) {
 int prod_idx = action_table[state][tidx].value;
 Production *prod = &grammar[prod_idx];

 printf("Reduce %c -> %s\n", prod->lhs, prod->rhs);

 int pop_count = strlen(prod->rhs) * 2;
 top -= pop_count;
 sym_top -= strlen(prod->rhs);

 int s = stack[top];
 int nt_idx = (prod->lhs == 'S') ? 0 : 1;
 int next_state = goto_table[s][nt_idx];

 symbols[sym_top++] = prod->lhs;
 stack[++top] = next_state;

 } else if (act == ACCEPT) {
 printf("Accept!\n");
 return true;

 } else {
 printf("Error!\n");
 return false;
 }
 }
}

// Print parsing tables
void print_tables() {
 printf("\n=== ACTION TABLE ===\n");
 printf("State\t");
 for (int i = 0; terminals[i] != '\0'; i++) {
 printf("%c\t", terminals[i]);
 }
 printf("\n");

 for (int i = 0; i < num_states; i++) {
 printf("%d\t", i);
 for (int j = 0; terminals[j] != '\0'; j++) {
 ActionEntry *ent = &action_table[i][j];
 if (ent->type == SHIFT) printf("s%d\t", ent->value);
 else if (ent->type == REDUCE) printf("r%d\t", ent->value);
 else if (ent->type == ACCEPT) printf("acc\t");
 else printf("\t");
 }
 printf("\n");
 }

 printf("\n=== GOTO TABLE ===\n");
 printf("State\tS\tC\n");
 for (int i = 0; i < num_states; i++) {
 printf("%d\t%d\t%d\n", i, goto_table[i][0], goto_table[i][1]);
 }
}

int main() {
 init_grammar();

 printf("=== Building SLR Parser ===\n");
 printf("Grammar:\n");
 printf(" S -> CC\n");
 printf(" C -> cC\n");
 printf(" C -> d\n");

 build_canonical_collection();
 printf("\nNumber of states: %d\n", num_states);

 build_parsing_tables();
 print_tables();

 // Parse input
 char input[] = "ccd$";
 bool result = parse_input(input);

 printf("\nParsing result: %s\n", result ? "SUCCESS" : "FAILED");

 return 0;
}
